patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..4d4c04ca78a4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5638,6 +5638,37 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
 Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
                                                   MinMaxIntrinsic *MinMax,
                                                   Value *Z, CmpPredicate Pred) {
+
+  // Handle the pattern: icmp eq Z, smin(smax(Z, Lo), Hi)
+  // This checks if Z is in range [Lo, Hi], which can be transformed to
+  // icmp ult (Z - Lo), (Hi - Lo + 1)
+  if (Pred == ICmpInst::ICMP_EQ && MinMax->isSigned() &&
+      MinMax->getIntrinsicID() == Intrinsic::smin) {
+    if (auto *InnerMinMax = dyn_cast<MinMaxIntrinsic>(MinMax->getLHS())) {
+      if (InnerMinMax->isSigned() &&
+          InnerMinMax->getIntrinsicID() == Intrinsic::smax &&
+          InnerMinMax->getLHS() == Z) {
+        const APInt *Lo, *Hi;
+        if (match(InnerMinMax->getRHS(), m_APInt(Lo)) &&
+            match(MinMax->getRHS(), m_APInt(Hi))) {
+          // Check that Lo <= Hi (valid range)
+          if (*Lo <= *Hi) {
+            unsigned BitWidth = I.getType()->getScalarSizeInBits();
+            APInt RangeSize = *Hi - *Lo + 1;
+            // Only optimize if the range fits in unsigned domain
+            // (i.e., no overflow when computing range size)
+            if (RangeSize.isNonNegative() && RangeSize.ule(APInt::getMaxValue(BitWidth))) {
+              // Create Z - Lo
+              Value *ZMinusLo = Builder.CreateSub(Z, ConstantInt::get(Z->getType(), *Lo));
+              // Create icmp ult (Z - Lo), RangeSize
+              return new ICmpInst(ICmpInst::ICMP_ULT, ZMinusLo,
+                                  ConstantInt::get(I.getType(), RangeSize));
+            }
+          }
+        }
+      }
+    }
+  }
   Value *X = MinMax->getLHS();
   Value *Y = MinMax->getRHS();
   if (ICmpInst::isSigned(Pred) && !MinMax->isSigned())
@@ -5649,6 +5680,7 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
     if (isKnownNonNegative(Z, SQ.getWithInstruction(&I)) &&
         isKnownNonNegative(MinMax, SQ.getWithInstruction(&I))) {
       Pred = ICmpInst::getFlippedSignednessPredicate(Pred);
+      Pred = ICmpInst::getFlippedSignednessPredicate(Pred);
     } else
       return nullptr;
   }

